const AWS = require('aws-sdk');  // Importing aws sdk in nodejs, it will allow us access S3 and API Gateway services from our lambda function  
AWS.config.update({region:'us-west-2'});    // Setting up the region for your service (replace 'your_aws_accesskey' with actual AWS Access Key) 
const s3 = new AWS.S3();     // Initialize S3 instance in NodeJS  
let id=0;      // Global variable to generate unique IDs, not used here but can be useful for tracking requests   
exports.handler = (event, context, callback) => {       // Exporting the handler function 
AWS.config.update({region:'us-west-2'});   // Setting up AWS region again in case it's changed during execution of lambda    
id++;      // Increment id for every request   
context.awsRequestId = id ;       // Set the aws Request ID 
let params={          // Parameters to be passed into S3 upload method  
Bucket: 'uploads',         // Name of bucket where you want your file saved, replace with actual name in AWS    
Key: `${id}.txt` ,       // Key for the object. The key is a combination of path and filename   
Body : event['body']      // File content to be uploaded  
}; 
s3.upload(params,(err)=> {         // Callback function after uploading file, it will call if there're no errors    
if (err){          // If error occurred during the process then log that and return back with an appropriate message   
console.log('Error', err); 
callback({"statusCode":501,"body":"An Error Occurred During File Upload."}, null) ;   } else {      // Otherwise, if everything is fine send a success response    
 callback(null ,{ "statusCode":200,    body: JSON.stringify('File uploaded successfully.'),  headers : {"Content-Type":"application/json"}});} });       };